{
  "id": "automation-001-setup-cronjob",
  "title": "Set Up Daily Database Optimization Cronjob",
  "description": "Developer wants to schedule a daily cronjob to run database optimization scripts for better application performance.",
  "domain": "automation",
  "prompt": "I need to set up a cronjob that runs every night at 3 AM to optimize our MySQL database. The script is located at /scripts/optimize-db.sh. Can you help me create this scheduled task and show me what cronjobs are already running?",
  "expectedDomains": ["automation", "project-foundation"],
  "expectedTools": [
    "project/list",
    "cronjob/list",
    "cronjob/create"
  ],
  "successCriteria": [
    {
      "description": "Existing cronjobs listed",
      "method": "log-pattern",
      "config": {
        "pattern": "cronjob/list",
        "minOccurrences": 1
      }
    },
    {
      "description": "New cronjob created",
      "method": "log-pattern",
      "config": {
        "pattern": "cronjob/create",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [
    { "resourceType": "cronjob", "identificationMethod": "log-parse", "deletionTool": "cronjob/delete", "order": 1 }
  ],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "My main website project" },
    { "questionPattern": "schedule|time|frequency", "answer": "Every day at 3:00 AM" },
    { "questionPattern": "email|notification", "answer": "Send email on failure only" },
    { "questionPattern": "timeout", "answer": "30 minutes max" }
  ],
  "estimatedDuration": 4,
  "timeout": 12,
  "priority": "P2",
  "tags": ["automation", "cronjob", "database", "maintenance"]
}

{
  "id": "automation-002-manage-scheduled-tasks",
  "title": "Review and Manage Scheduled Tasks",
  "description": "Admin needs to review all scheduled cronjobs, check recent execution history, and manually trigger a job for testing.",
  "domain": "automation",
  "prompt": "I want to review all the scheduled tasks we have running. Can you list all cronjobs, show me the execution history of the main cleanup job, and trigger it manually so I can verify it works correctly?",
  "expectedDomains": ["automation", "project-foundation"],
  "expectedTools": [
    "project/list",
    "cronjob/list",
    "cronjob/get",
    "cronjob/execution/list",
    "cronjob/trigger"
  ],
  "successCriteria": [
    {
      "description": "Cronjobs listed",
      "method": "log-pattern",
      "config": {
        "pattern": "cronjob/list",
        "minOccurrences": 1
      }
    },
    {
      "description": "Execution history retrieved",
      "method": "log-pattern",
      "config": {
        "pattern": "execution",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "The production website" },
    { "questionPattern": "which cronjob|which task", "answer": "The database cleanup job" },
    { "questionPattern": "confirm|sure", "answer": "Yes, trigger it now" }
  ],
  "estimatedDuration": 3,
  "timeout": 10,
  "priority": "P3",
  "tags": ["automation", "cronjob", "monitoring", "execution"]
}

{
  "id": "backups-001-setup-backup-schedule",
  "title": "Configure Automated Backup Schedule",
  "description": "Admin wants to set up an automated daily backup schedule for their production project to ensure data protection.",
  "domain": "backups",
  "prompt": "I need to make sure our production site is properly backed up. Can you set up a daily automated backup schedule? I want backups to run every night and keep the last 14 days of backups. Also show me if there are any existing backup schedules.",
  "expectedDomains": ["backups", "project-foundation"],
  "expectedTools": [
    "project/list",
    "backup/schedule/list",
    "backup/schedule/create"
  ],
  "successCriteria": [
    {
      "description": "Backup schedules listed",
      "method": "log-pattern",
      "config": {
        "pattern": "backup/schedule",
        "minOccurrences": 1
      }
    },
    {
      "description": "New schedule created",
      "method": "log-pattern",
      "config": {
        "pattern": "schedule/create",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [
    { "resourceType": "backup", "identificationMethod": "log-parse", "deletionTool": "backup/schedule/delete", "order": 1 }
  ],
  "questionAnswers": [
    { "questionPattern": "which project", "answer": "The main production project" },
    { "questionPattern": "time|when|schedule", "answer": "Every night at 2 AM" },
    { "questionPattern": "retention|keep|days", "answer": "Keep 14 days of backups" }
  ],
  "estimatedDuration": 4,
  "timeout": 12,
  "priority": "P1",
  "tags": ["backups", "schedule", "automation", "data-protection"]
}

